import { NgModule } from '@angular/core';
import { Routes, RouterModule } from '@angular/router';

import { MainComponent } from './main.component';

const routes: Routes = [
  {
    path: '',
    component: MainComponent,
    children: [
      { path: '', redirectTo: '/projects', pathMatch: 'full' },
      { path: 'projects', loadChildren: () => import('../projects/projects.module').then(m => m.ProjectsModule) },
      { path: 'request-bid', loadChildren: () => import('../request-bid/request-bid.module').then(m => m.RequestBidModule) },
      { path: 'request-submittal', loadChildren: () => import('../request-submittal/request-submittal.module').then(m => m.RequestSubmittalModule) },
      { path: 'project-detail', loadChildren: () => import('../project-detail/project-detail.module').then(m => m.RequestProjectDetailModule) },
    ]
  },
];

@NgModule({
  imports: [RouterModule.forChild(routes)],
  exports: [RouterModule]
})
export class MainRoutingModule { }
