import { Component, OnInit } from '@angular/core';

import { AuthService } from '../../core/services/auth.service';


@Component({
  selector: 'app-main',
  templateUrl: './main.component.html',
  styleUrls: ['./main.component.scss']
})
export class MainComponent implements OnInit {

  constructor(private authService: AuthService) { }

  ngOnInit() {
    this.fetchUserDetails();
  }

  private async fetchUserDetails(): Promise<void> {
    try {
      const user = await this.authService.getUser();
      if (user && user.profile && user.profile.wallpaper) {
        document.body.style.background = `url("${user.profile.wallpaper}") no-repeat center center fixed`;
        document.body.style.backgroundSize = 'cover';
      }
    } catch (error) {
      console.log('Error in MainComponent.fetchUserDetails', error);
    }
  }
}
