import { Component, OnInit, HostListener } from '@angular/core';

import { AuthService } from '../../../core/services/auth.service';

import { UserModel } from '../../../core/models/server/models';


@Component({
  selector: 'app-nav-bar',
  templateUrl: './nav-bar.component.html',
  styleUrls: ['./nav-bar.component.scss']
})
export class NavBarComponent implements OnInit {
  public user: UserModel;
  public profileBoxIsOpen = true;


  constructor(private authService: AuthService) { }

  ngOnInit() {
    this.fetchUserDetails();
  }

  private async fetchUserDetails(): Promise<void> {
    try {
      this.user = await this.authService.getUser();
    } catch (error) {
      console.log('Error in NavBarComponent.fetchUserDetails', error);
    } finally {
      setTimeout(() => this.setProfileBoxPosition(), 100);
    }
  }

  private setProfileBoxPosition(): void {
    const profileButton = document.getElementById('appNavBar_profileButton');
    const profileBox = document.getElementById('appNavBar_profileBox');
    const profileBoxRect = profileBox.getBoundingClientRect();
    const bodyRect = document.body.getBoundingClientRect();
    const profileButtonRect = profileButton.getBoundingClientRect();

    const middleOffset = profileButtonRect.width / 2 - profileBoxRect.width / 2;
    const right1 = profileBoxRect.right + middleOffset;
    const right2 = bodyRect.right - 15;
    const xTranslate = right1 <= right2 ? middleOffset : right2 - profileBoxRect.right;
    const yTranslate = profileButtonRect.height + 15;

    profileBox.style.transform = `translate3d(${xTranslate}px, ${yTranslate}px, 0)`;
    profileBox.style.visibility = 'visible';
    this.profileBoxIsOpen = false;
  }

  @HostListener('document:click')
  public onDocumentClick(): void {
    this.profileBoxIsOpen = false;
  }

  public toggleProfileBox(event: MouseEvent): void {
    this.profileBoxIsOpen = !this.profileBoxIsOpen;
    event.stopPropagation();
  }

  public onProfileBoxClick(event: MouseEvent): void {
    setTimeout(() => this.profileBoxIsOpen = false, 300);
    event.stopPropagation();
  }
}
