import { Component, OnInit, Input } from '@angular/core';

import { Step, Connector, Properties } from '../../core/models/step-progress-bar.model';


@Component({
  selector: 'app-step-progress-bar',
  templateUrl: './step-progress-bar.component.html',
  styleUrls: ['./step-progress-bar.component.scss']
})
export class StepProgressBarComponent implements OnInit {
  private _steps: Step[] = [];
  private _properties: Properties;

  public connectors: Connector[] = [];
  public connectorWidth = '';
  public connectorHeight = '';
  public connectorTop = '';
  public iconSize = '';

  @Input() set steps(value: Step[]) {
    this._steps = value;
    this.setConnectors();
    this.setConnectorProperties();
  };

  get steps(): Step[] {
    return this._steps;
  }

  @Input() set properties(value: Properties) {
    this._properties = value;
    this.setConnectorProperties();
  }

  get properties(): Properties {
    return this._properties;
  }


  constructor() { }

  ngOnInit() {
  }

  private setConnectors(): void {
    this.connectors = [];

    if (!this._steps || !this._steps.length) {
      return;
    }

    const percent = Math.floor(100 / this._steps.length);
    const halfPercent = Math.floor(percent / 2);

    for (let i = 1; i < this._steps.length; i++) {
      this.connectors.push({ left: (percent * (i - 1) + halfPercent) + '%', active: this._steps[i].passed });
    }
  }

  private setConnectorProperties(): void {
    if (!this._properties || !this._steps || !this._steps.length) {
      return;
    }

    this.connectorWidth = Math.floor(100 / this._steps.length) + '%';
    this.connectorHeight = this._properties.connectorHeight + 'px';
    this.connectorTop = `${this._properties.iconSize / 2 - this._properties.connectorHeight / 2}px`;
    this.iconSize = this._properties.iconSize + 'px';
  }
}
