import { Component } from '@angular/core';


@Component({
    selector: 'app-wait-spinner',
    template: `
      <div style="text-align:center">
        <mat-spinner [strokeWidth]="5" [diameter]="50" style="margin:auto"></mat-spinner>
        <div style="margin-top:15px;user-select: none;">Please Wait...</div>
      </div>
    `
})
export class WaitSpinnerComponent { }
